import ReactQuill from "react-quill-new";
import "react-quill-new/dist/quill.snow.css";

interface HarmonyRichTextProps {
  value: string;
  onChange: (content: string) => void;
  readOnly?: boolean;
  placeholder?: string;
  className?: string;
}

const modules = {
  toolbar: [
    [{ header: [1, 2, 3, false] }],
    ["bold", "italic", "underline", "strike"],
    [{ list: "ordered" }, { list: "bullet" }],
    [{ color: [] }, { background: [] }],
    ["link", "image", "clean"],
  ],
};

const formats = [
  "header",
  "bold", "italic", "underline", "strike",
  "list", "bullet",
  "color", "background",
  "link", "image",
];

const HarmonyRichText = ({
  value,
  onChange,
  readOnly = false,
  placeholder = "Start typing...",
  className = "",
}: HarmonyRichTextProps) => {
  return (
    <div className={`quill-container ${className} ${readOnly ? "quill-read-only" : ""}`}>
      <ReactQuill
        theme="snow"
        modules={readOnly ? { toolbar: false } : modules}
        readOnly={readOnly}
        formats={formats}
        placeholder={placeholder}
        value={value || ""}
        onChange={onChange}
      />
    </div>
  );
};

export default HarmonyRichText;
