/* ============================
   TYPES
   ============================ */

export type FormMode = "read" | "create" | "edit" | "delete" | "approve" | "reject";

export interface FieldOption {
    value: string | number;
    label: string;
}

export interface ValidationRule {
    type: string;
    value?: any;
    message: string;
}

export interface FieldMetadata {
    name: string;
    label: string;
    inputType: string;
    required?: boolean;
    isNullable?: boolean;
    isReadOnly?: boolean;
    placeholder?: string;
    description?: string;
    group?: string;
    order?: number;
    defaultValue?: string;
    step?: number;
    format?: string;
    accept?: string;
    multiple?: boolean;
    maxSizeInBytes?: number;
    options?: FieldOption[];
    validations?: ValidationRule[];
    itemSchema?: FormSchema;
    nestedSchema?: FormSchema;
}

export interface FormSchema {
    formKey: string;
    title: string;
    fields: FieldMetadata[];
}

interface HarmonyFormProps {
    /** Backend DTO class name — fetches field metadata from `GET /api/forms/{dtoName}?mode={mode}`. */
    dtoName?: string;
    /** Supply a pre-built schema to skip the API fetch entirely (useful for unit tests or static forms). */
    schema?: FormSchema | null;
    /** Called on valid submission with a `Record<string, any>` whose keys are PascalCase DTO field names. */
    onSubmit: (data: any) => void;
    /** Renders a Cancel/Close button; label is "Close" in read/delete mode, "Cancel" otherwise. */
    onCancel?: () => void;
    /** Renders a Delete button — only visible in read/delete mode (for confirmation flows). */
    onDelete?: () => void | Promise<void>;
    /** Alias for `initialValues`; takes precedence when both are supplied. */
    defaultValues?: Record<string, any> | null;
    /**
     * Pre-fills the form. Keys are matched case-insensitively against DTO field names, so both
     * `{ userId: "x" }` and `{ UserId: "x" }` work. Date strings are sliced to `yyyy-MM-dd` /
     * `yyyy-MM-ddTHH:mm` automatically. Nested objects and collections are normalised recursively.
     */
    initialValues?: Record<string, any> | null;
    /** Label for the built-in submit button. Defaults to `"Submit Changes"`. */
    submitLabel?: string;
    /** Hide the built-in submit button when an external footer triggers submission via `form.requestSubmit()`. */
    hideSubmitButton?: boolean;
    /** Disables the submit button and shows a spinner while a mutation is in flight. */
    isPending?: boolean;
    /**
     * Controls which backend fields are rendered and whether they are editable.
     * `"read"` and `"delete"` disable all inputs. The backend filters fields by
     * `VisibleIn` / `EditableIn` arrays on each `[FormField]` attribute.
     * Defaults to `"create"`.
     */
    mode?: FormMode;
    /**
     * Fires after every field change with `(fieldName, newValue, allCurrentValues)`.
     * `fieldName` uses the PascalCase DTO field name (e.g. `"LeaveDate"`).
     * Use this to watch specific fields and drive side-effects outside the form
     * (e.g. triggering an async balance-validation check).
     */
    onFieldChange?: (fieldName: string, value: any, allValues: Record<string, any>) => void;
}

/* ============================
   HELPERS
   ============================ */

function buildDefaultValues(schemaData: FormSchema): Record<string, any> {
    const defaults: Record<string, any> = {};
    schemaData.fields.forEach((field) => {
        if (field.defaultValue != null) {
            defaults[field.name] = field.defaultValue;
        } else if (field.inputType === "collection" || field.inputType === "multiselect") {
            defaults[field.name] = [];
        } else if (field.inputType === "object" && field.nestedSchema) {
            defaults[field.name] = buildDefaultValues(field.nestedSchema);
        } else if (field.inputType === "checkbox" || field.inputType === "boolean") {
            defaults[field.name] = false;
        }
    });
    return defaults;
}

const getFieldStyles = (error: any) =>
    cn(
        "px-3 rounded-xl border bg-card text-sm font-medium text-foreground transition-all",
        "focus:outline-none focus:ring-2 focus:ring-ring/20",
        error ? "border-destructive focus:ring-destructive/20" : "border-border hover:border-ring/50"
    );

/* ============================
   SUB-COMPONENTS
   ============================ */

const FieldLabelRow = ({ field, fieldId }: { field: FieldMetadata; fieldId: string }) => (
    <div className="flex items-center gap-1.5">
        <Label htmlFor={fieldId} className="text-sm font-medium text-foreground">
            {field.label}
            {field.required && <span className="text-destructive ml-0.5">*</span>}
        </Label>
        {field.description && (
            <Tooltip>
                <TooltipTrigger asChild>
                    <Info size={13} className="text-muted-foreground cursor-help shrink-0" />
                </TooltipTrigger>
                <TooltipContent side="top">{field.description}</TooltipContent>
            </Tooltip>
        )}
    </div>
);

const MultiSelectField = ({ field, value, onChange, error, id, disabled = false }: any) => {
    const [isOpen, setIsOpen] = useState(false);
    const selectedValues = Array.isArray(value) ? value.map((val: any) => String(val)) : [];
    const selectedLabels = field.options
        ?.filter((opt: any) => selectedValues.includes(String(opt.value)))
        .map((opt: any) => opt.label)
        .join(", ");

    return (
        <div className="relative">
            <button
                id={id}
                type="button"
                onClick={() => !disabled && setIsOpen((prev) => !prev)}
                disabled={disabled}
                className={cn(
                    getFieldStyles(error),
                    "flex items-center justify-between gap-3 text-left w-full h-11.5",
                    "disabled:opacity-50 disabled:cursor-not-allowed"
                )}
                aria-expanded={isOpen}
                aria-haspopup="listbox"
            >
                <span className="truncate">
                    {selectedLabels || `Select ${field.label}...`}
                </span>
                <ChevronDown size={16} className={`transition-transform ${isOpen ? "rotate-180" : ""}`} />
            </button>
            {isOpen && !disabled && (
                <div className="absolute z-10 w-full mt-2 rounded-xl border border-slate-200 bg-white shadow-xl p-2 max-h-60 overflow-y-auto space-y-1">
                    {field.options?.map((opt: any) => {
                        const optionValue = String(opt.value);
                        const isChecked = selectedValues.includes(optionValue);
                        return (
                            <label
                                key={optionValue}
                                className={cn(
                                    "flex items-center gap-3 rounded-lg px-3 py-2 text-[13px] transition cursor-pointer",
                                    isChecked ? "bg-indigo-50/70" : "hover:bg-slate-50"
                                )}
                            >
                                <input
                                    type="checkbox"
                                    className="h-4 w-4 rounded border-slate-300 text-indigo-600 focus:ring-indigo-500/20 cursor-pointer"
                                    checked={isChecked}
                                    onChange={(e) => {
                                        if (e.target.checked) {
                                            onChange([...selectedValues, optionValue]);
                                        } else {
                                            onChange(selectedValues.filter((v: string) => v !== optionValue));
                                        }
                                    }}
                                />
                                <span className="select-none font-medium">{opt.label}</span>
                            </label>
                        );
                    })}
                </div>
            )}
        </div>
    );
};

const FormInputSnippet = ({
    field,
    value,
    onChange,
    error,
    id,
    disabled = false,
    isViewMode = false,
}: {
    field: FieldMetadata;
    value: any;
    onChange: (v: any) => void;
    error?: any;
    id: string;
    disabled?: boolean;
    isViewMode?: boolean;
}) => {
    if (field.inputType === "collection" || field.inputType === "object") return null;

    const placeholder = field.placeholder ?? `Enter ${field.label.toLowerCase()}...`;

    // QUILL / RICH TEXT
    if (field.inputType === "quill") {
        return (
            <>
                <div
                    className={cn(
                        "bg-card rounded-xl border overflow-hidden transition-all",
                        !disabled && "focus-within:border-ring focus-within:ring-2 focus-within:ring-ring/20",
                        error ? "border-destructive" : "border-border"
                    )}
                >
                    <HarmonyRichText
                        value={value ?? ""}
                        onChange={onChange}
                        readOnly={disabled}
                        placeholder={placeholder}
                    />
                </div>
                {error?.message && <p className="text-xs text-destructive mt-1">{error.message}</p>}
            </>
        );
    }

    // CHECKBOX / BOOLEAN — label rendered inline; FieldLabelRow is skipped for this type
    if (field.inputType === "checkbox" || field.inputType === "boolean") {
        return (
            <div className="flex items-center gap-3 h-11">
                <Checkbox
                    id={id}
                    checked={Boolean(value)}
                    onCheckedChange={(checked) => !disabled && onChange(Boolean(checked))}
                    disabled={disabled}
                    aria-invalid={error ? true : undefined}
                />
                <div className="flex items-center gap-1.5">
                    <Label
                        htmlFor={id}
                        className={cn(
                            "text-sm font-medium text-foreground",
                            disabled ? "cursor-default opacity-70" : "cursor-pointer"
                        )}
                    >
                        {field.label}
                        {field.required && <span className="text-destructive ml-0.5">*</span>}
                    </Label>
                    {field.description && (
                        <Tooltip>
                            <TooltipTrigger asChild>
                                <Info size={13} className="text-muted-foreground cursor-help" />
                            </TooltipTrigger>
                            <TooltipContent side="top">{field.description}</TooltipContent>
                        </Tooltip>
                    )}
                </div>
            </div>
        );
    }

    // MULTISELECT
    if (field.inputType === "multiselect") {
        return (
            <>
                <MultiSelectField
                    field={field}
                    value={value}
                    onChange={onChange}
                    error={error}
                    id={id}
                    disabled={disabled}
                />
                {error?.message && <p className="text-xs text-destructive mt-1">{error.message}</p>}
            </>
        );
    }

    // SELECT
    if (field.inputType === "select" || (Array.isArray(field.options) && field.inputType !== "radio")) {
        return (
            <>
                <Select
                    value={String(value ?? "")}
                    onValueChange={(v) => onChange(v)}
                    disabled={disabled}
                >
                    <SelectTrigger
                        className="w-full"
                        disabled={disabled}
                        aria-invalid={error ? true : undefined}
                    >
                        <SelectValue placeholder={field.placeholder ?? `Select ${field.label}...`} />
                    </SelectTrigger>
                    <SelectContent>
                        {field.options?.map((opt: any) => (
                            <SelectItem key={opt.value} value={String(opt.value)}>
                                {opt.label}
                            </SelectItem>
                        ))}
                    </SelectContent>
                </Select>
                {error?.message && <p className="text-xs text-destructive mt-1">{error.message}</p>}
            </>
        );
    }

    // RADIO
    if (field.inputType === "radio") {
        return (
            <>
                <RadioGroup
                    value={String(value ?? "")}
                    onValueChange={(v) => onChange(v)}
                    className="flex flex-col gap-2"
                    aria-labelledby={`${id}-label`}
                >
                    {field.options?.map((opt: any) => (
                        <div
                            key={opt.value}
                            className={cn(
                                "flex flex-1 min-w-35 items-center gap-3 p-3 rounded-lg border border-border bg-card transition-all hover:shadow-sm",
                                !disabled && "cursor-pointer hover:bg-accent"
                            )}
                        >
                            <RadioGroupItem
                                value={String(opt.value)}
                                id={`${id}-${opt.value}`}
                                disabled={disabled}
                            />
                            <Label
                                htmlFor={`${id}-${opt.value}`}
                                className={cn(
                                    "text-xs font-bold text-muted-foreground uppercase tracking-tight",
                                    !disabled && "hover:text-foreground cursor-pointer"
                                )}
                            >
                                {opt.label}
                            </Label>
                        </div>
                    ))}
                </RadioGroup>
                {error?.message && <p className="text-xs text-destructive mt-1">{error.message}</p>}
            </>
        );
    }

    // TEXTAREA
    if (field.inputType === "textarea") {
        return (
            <>
                <Textarea
                    id={id}
                    value={value ?? ""}
                    onChange={(e) => onChange(e.target.value)}
                    rows={4}
                    placeholder={placeholder}
                    disabled={disabled}
                    aria-invalid={error ? true : undefined}
                />
                {error?.message && <p className="text-xs text-destructive mt-1">{error.message}</p>}
            </>
        );
    }

    // FILE — view mode shows a link; edit mode shows native file input
    if (field.inputType === "file") {
        if (isViewMode) {
            if (value) {
                return (
                    <a
                        href={String(value)}
                        target="_blank"
                        rel="noopener noreferrer"
                        className="inline-flex items-center gap-2 text-sm font-medium text-primary underline underline-offset-2 hover:text-primary/80 transition-colors"
                    >
                        <ExternalLink size={14} />
                        {String(value).split("/").pop() || "View File"}
                    </a>
                );
            }
            return <span className="text-sm text-muted-foreground italic">No file attached</span>;
        }
        return (
            <input
                id={id}
                type="file"
                accept={field.accept}
                multiple={field.multiple}
                onChange={(e) => onChange(e.target.files?.[0] ?? null)}
                className="block w-full text-sm text-foreground file:mr-4 file:py-2 file:px-4 file:rounded-lg file:border-0 file:text-sm file:font-medium file:bg-primary/10 file:text-primary hover:file:bg-primary/20 cursor-pointer disabled:opacity-50 disabled:cursor-not-allowed"
            />
        );
    }

    // CURRENCY — number input with ₹ prefix
    if (field.inputType === "currency") {
        return (
            <Input
                id={id}
                type="number"
                step={field.step ?? 0.01}
                value={value ?? ""}
                onChange={(e: React.ChangeEvent<HTMLInputElement>) => {
                    const val = e.target.value;
                    onChange(val === "" ? "" : Number(val));
                }}
                placeholder={field.placeholder ?? "0.00"}
                disabled={disabled}
                error={error?.message}
                leftIcon={
                    <span className="text-sm font-medium text-muted-foreground select-none">₹</span>
                }
            />
        );
    }

    // DEFAULT: text, email, password, tel, number, uuid, date, datetime, time, url
    // Map metadata input types to HTML input types
    const htmlType =
        field.inputType === "datetime" ? "datetime-local" :
        field.inputType === "uuid"     ? "text" :
        field.inputType;

    const getInputIcon = () => {
        if (field.inputType === "number")                               return <Hash size={14} />;
        if (field.inputType === "date" || field.inputType === "datetime") return <CalendarIcon size={14} />;
        if (field.inputType === "time")                                 return <Clock size={14} />;
        if (field.inputType === "email")                                return <Mail size={14} />;
        if (field.inputType === "tel")                                  return <Phone size={14} />;
        if (field.inputType === "url")                                  return <ExternalLink size={14} />;
        if (field.inputType === "file")                                 return <FileText size={14} />;
        return <Type size={14} />;
    };

    return (
        <Input
            id={id}
            type={htmlType}
            value={value ?? ""}
            onChange={(e: React.ChangeEvent<HTMLInputElement>) => {
                const val = e.target.value;
                onChange(field.inputType === "number" ? (val === "" ? "" : Number(val)) : val);
            }}
            placeholder={placeholder}
            step={field.step && field.inputType === "number" ? field.step : undefined}
            disabled={disabled}
            error={error?.message}
            leftIcon={getInputIcon()}
        />
    );
};

const FormFieldsRecursive = ({
    schema,
    prefix = "",
    instanceId,
    isViewMode = false,
    onFieldChange,
}: {
    schema: FormSchema;
    prefix?: string;
    instanceId: string;
    isViewMode?: boolean;
    onFieldChange?: (fieldName: string, value: any, allValues: Record<string, any>) => void;
}) => {
    const { control, formState: { errors }, getValues } = useFormContext();

    const getValidationRules = (field: FieldMetadata) => {
        if (isViewMode) return {};

        const rules: any = {};

        if (!field.validations) {
            if (field.required) rules.required = "This field is required";
            return rules;
        }

        field.validations.forEach((rule) => {
            switch (rule.type) {
                case "required":
                    rules.required = rule.message || "Required";
                    break;
                case "email":
                    rules.validate = {
                        ...rules.validate,
                        email: (val: string) =>
                            !val || /^[^\s@]+@[^\s@]+\.[^\s@]+$/.test(val) || rule.message,
                    };
                    break;
                case "phone":
                    rules.validate = {
                        ...rules.validate,
                        phone: (val: string) =>
                            !val || /^\+?[\d\s\-\(\)]{10,15}$/.test(val) || rule.message,
                    };
                    break;
                case "url":
                    rules.validate = {
                        ...rules.validate,
                        url: (val: string) =>
                            !val || /^https?:\/\/.+/.test(val) || rule.message,
                    };
                    break;
                case "regex":
                    rules.pattern = {
                        value: new RegExp(String(rule.value)),
                        message: rule.message || "Invalid format",
                    };
                    break;
                case "minLength":
                    rules.minLength = { value: Number(rule.value), message: rule.message };
                    break;
                case "maxLength":
                    rules.maxLength = { value: Number(rule.value), message: rule.message };
                    break;
                case "compare": {
                    const otherField = String(rule.value);
                    rules.validate = {
                        ...rules.validate,
                        compare: (val: string, formValues: any) =>
                            val === formValues[otherField] || rule.message,
                    };
                    break;
                }
                case "range": {
                    const range = rule.value as { min?: number; max?: number } | undefined;
                    rules.validate = {
                        ...rules.validate,
                        range: (val: any) => {
                            const num = Number(val);
                            if (range?.min != null && num < range.min) return rule.message;
                            if (range?.max != null && num > range.max) return rule.message;
                            return true;
                        },
                    };
                    break;
                }
            }
        });

        if (field.required && !rules.required) rules.required = "This field is required";
        return rules;
    };

    const sorted = [...schema.fields].sort(
        (a, b) => (a.order ?? Number.MAX_SAFE_INTEGER) - (b.order ?? Number.MAX_SAFE_INTEGER)
    );

    // Segment fields into sections by group, preserving order
    type Section = { groupName: string | null; fields: FieldMetadata[] };
    const sections: Section[] = [];
    for (const field of sorted) {
        const groupName = field.group ?? null;
        const last = sections[sections.length - 1];
        if (!last || last.groupName !== groupName) {
            sections.push({ groupName, fields: [field] });
        } else {
            last.fields.push(field);
        }
    }

    const renderField = (field: FieldMetadata) => {
        const fieldName = prefix ? `${prefix}.${field.name}` : field.name;
        const fieldId = `${instanceId}-${fieldName}`.replace(/\./g, "-");
        const error = fieldName.split(".").reduce((obj: any, key) => obj?.[key], errors);
        const isDisabled = isViewMode || !!field.isReadOnly;

        const showLabelRow =
            field.inputType !== "checkbox"   &&
            field.inputType !== "boolean"    &&
            field.inputType !== "object"     &&
            field.inputType !== "collection";

        return (
            <div
                key={fieldName}
                className="flex flex-col gap-2 animate-in fade-in slide-in-from-bottom-3 duration-700"
            >
                {showLabelRow && <FieldLabelRow field={field} fieldId={fieldId} />}

                <Controller
                    name={fieldName}
                    control={control}
                    rules={getValidationRules(field)}
                    render={({ field: { value, onChange } }) => {
                        const wrappedOnChange = onFieldChange
                            ? (newValue: any) => {
                                  onChange(newValue);
                                  onFieldChange(fieldName, newValue, { ...getValues(), [fieldName]: newValue });
                              }
                            : onChange;
                        return (
                            <>
                                <FormInputSnippet
                                    field={field}
                                    value={value}
                                    onChange={wrappedOnChange}
                                    error={error}
                                    id={fieldId}
                                    disabled={isDisabled}
                                    isViewMode={isViewMode}
                                />

                                {/* NESTED OBJECT */}
                                {field.inputType === "object" && field.nestedSchema && (
                                    <div className="bg-muted/30 p-6 rounded-xl border border-border space-y-6">
                                        <div className="flex flex-col gap-0.5">
                                            <p className="text-[10px] font-bold text-primary uppercase tracking-widest">
                                                {field.label}
                                            </p>
                                            <p className="text-[9px] text-muted-foreground font-bold uppercase tracking-widest">
                                                Linked Group Configuration
                                            </p>
                                        </div>
                                        <FormFieldsRecursive
                                            schema={field.nestedSchema}
                                            prefix={fieldName}
                                            instanceId={instanceId}
                                            isViewMode={isViewMode}
                                            onFieldChange={onFieldChange}
                                        />
                                    </div>
                                )}

                                {/* NESTED COLLECTION */}
                                {field.inputType === "collection" && field.itemSchema && (
                                    <div className="space-y-6 mt-4">
                                        <div className="flex items-center gap-4">
                                            <div className="w-8 h-8 rounded-lg bg-primary/10 flex items-center justify-center border border-primary/20">
                                                <RefreshCw size={14} className="text-primary" />
                                            </div>
                                            <div className="flex flex-col">
                                                <span className="text-[11px] font-black text-foreground uppercase tracking-widest">
                                                    {field.label} Registry
                                                </span>
                                                <span className="text-[9px] font-bold text-muted-foreground uppercase tracking-tighter">
                                                    Multiple records supported
                                                </span>
                                            </div>
                                            <div className="h-px bg-border flex-1" />
                                        </div>
                                        <div className="flex flex-col gap-8">
                                            {(Array.isArray(value) ? value : [{}]).map((_: any, idx: number) => (
                                                <div
                                                    key={idx}
                                                    className="bg-card p-8 sm:p-10 rounded-2xl border border-border border-l-4 border-l-primary space-y-8 relative shadow-sm hover:shadow-md transition-all"
                                                >
                                                    <div className="absolute -top-3 right-8">
                                                        <span className="px-3 py-1 bg-primary text-primary-foreground text-[9px] font-black uppercase tracking-widest rounded-full shadow-sm">
                                                            #{idx + 1}
                                                        </span>
                                                    </div>
                                                    <FormFieldsRecursive
                                                        schema={field.itemSchema!}
                                                        prefix={`${fieldName}.${idx}`}
                                                        instanceId={instanceId}
                                                        isViewMode={isViewMode}
                                                        onFieldChange={onFieldChange}
                                                    />
                                                </div>
                                            ))}
                                        </div>
                                    </div>
                                )}
                            </>
                        );
                    }}
                />
            </div>
        );
    };

    return (
        <div className="flex flex-col gap-6">
            {sections.map((section, sectionIdx) => (
                <React.Fragment key={sectionIdx}>
                    {section.groupName && (
                        <div className="flex items-center gap-3 pt-2">
                            <h4 className="text-[10px] font-black text-muted-foreground uppercase tracking-widest whitespace-nowrap">
                                {section.groupName}
                            </h4>
                            <div className="h-px flex-1 bg-border" />
                        </div>
                    )}
                    {section.fields.map(renderField)}
                </React.Fragment>
            ))}
        </div>
    );
};

/* ============================
   MAIN COMPONENT
   ============================ */

const HarmonyForm: React.FC<HarmonyFormProps> = ({
    dtoName,
    schema: manualSchema,
    onSubmit,
    onCancel,
    onDelete,
    defaultValues = null,
    initialValues = null,
    submitLabel,
    hideSubmitButton = false,
    isPending = false,
    mode = "create",
    onFieldChange,
}) => {
    const instanceId = useId();
    const isViewMode = mode === "read" || mode === "delete";

    const [schema, setSchema] = useState<FormSchema | null>(null);
    const [loadError, setLoadError] = useState<string | null>(null);
    const [loading, setLoading] = useState(true);
    const [retryTrigger, setRetryTrigger] = useState(0);

    const effectiveValues = useMemo(
        () => defaultValues || initialValues,
        [defaultValues, initialValues]
    );
    const methods = useForm({ mode: "onChange" });

    const normalizeData = useCallback((values: any, schemaData: FormSchema): any => {
        if (!values || !schemaData?.fields) return values;
        const mapped: any = { ...values };

        schemaData.fields.forEach((field) => {
            const rawKey = Object.keys(values).find(
                (k) => k.toLowerCase() === field.name.toLowerCase()
            );
            const value = rawKey ? values[rawKey] : undefined;

            if (value === undefined || value === null || value === "") {
                if (field.inputType === "collection") mapped[field.name] = [];
                else if (field.inputType === "object") mapped[field.name] = {};
                else mapped[field.name] = null;
                return;
            }

            if (field.inputType === "collection" && field.itemSchema && Array.isArray(value)) {
                mapped[field.name] = value.map((v: any) => normalizeData(v, field.itemSchema!));
                return;
            }

            if (field.inputType === "object" && field.nestedSchema) {
                mapped[field.name] = normalizeData(value, field.nestedSchema);
                return;
            }

            if (typeof value === "string" && value.includes("T")) {
                if (field.inputType === "date") {
                    mapped[field.name] = value.split("T")[0];
                    return;
                }
                if (field.inputType === "datetime") {
                    mapped[field.name] = value.slice(0, 16);
                    return;
                }
            }

            mapped[field.name] = value;
        });

        return mapped;
    }, []);

    const fetchSchema = useCallback(async () => {
        if (!dtoName) return;
        try {
            setLoading(true);
            const data = await formMetadataService.getFormMetadata(dtoName, mode);
            setSchema(data);
            setLoadError(null);
        } catch (err: any) {
            setLoadError(err.message || "Failed to load form metadata");
        } finally {
            setLoading(false);
        }
    }, [dtoName, mode]);

    useEffect(() => {
        if (manualSchema) {
            setSchema(manualSchema);
            setLoading(false);
            return;
        }
        if (dtoName) fetchSchema();
    }, [fetchSchema, retryTrigger, manualSchema, dtoName]);

    useEffect(() => {
        if (!schema) return;
        const values = effectiveValues
            ? normalizeData(effectiveValues, schema)
            : buildDefaultValues(schema);
        methods.reset(values);
    }, [schema, effectiveValues, normalizeData, methods]);

    if (loading) {
        return (
            <div className="p-10 space-y-6">
                <div className="h-14 bg-muted rounded-xl animate-pulse" />
                <div className="h-14 bg-muted rounded-xl animate-pulse" />
                <div className="h-3 bg-muted rounded-full w-1/4 animate-pulse" />
                <div className="h-40 bg-muted rounded-xl animate-pulse" />
            </div>
        );
    }

    if (loadError) {
        return (
            <div className="p-10 bg-destructive/5 border border-destructive/20 rounded-xl flex flex-col items-center gap-6 text-center">
                <div className="w-16 h-16 bg-card rounded-2xl flex items-center justify-center shadow-sm text-destructive ring-4 ring-destructive/10">
                    <AlertCircle className="w-8 h-8" />
                </div>
                <div>
                    <h4 className="text-destructive font-black text-lg uppercase tracking-widest">
                        Configuration Error
                    </h4>
                    <p className="text-destructive/70 text-sm font-medium mt-1 max-w-xs mx-auto">
                        {loadError}
                    </p>
                </div>
                <Button
                    type="button"
                    variant="destructive"
                    onClick={() => setRetryTrigger((t) => t + 1)}
                >
                    <RefreshCw className="w-4 h-4" />
                    Retry
                </Button>
            </div>
        );
    }

    if (!schema) return null;

    return (
        <TooltipProvider>
            <FormProvider {...methods}>
                <form onSubmit={methods.handleSubmit(onSubmit)} className="space-y-12">
                    <FormFieldsRecursive
                        schema={schema}
                        instanceId={instanceId}
                        isViewMode={isViewMode}
                        onFieldChange={onFieldChange}
                    />

                    <div className="pt-8 flex items-center justify-end gap-3">
                        {onCancel && (
                            <Button type="button" variant="outline" onClick={onCancel}>
                                {isViewMode ? "Close" : "Cancel"}
                            </Button>
                        )}
                        {isViewMode ? (
                            onDelete && (
                                <Button
                                    type="button"
                                    variant="destructive"
                                    onClick={onDelete}
                                    disabled={isPending}
                                >
                                    {isPending ? (
                                        <>
                                            <Loader2 className="w-4 h-4 animate-spin" />
                                            Deleting...
                                        </>
                                    ) : (
                                        "Delete"
                                    )}
                                </Button>
                            )
                        ) : (
                            !hideSubmitButton && (
                                <Button
                                    type="submit"
                                    disabled={methods.formState.isSubmitting || isPending}
                                >
                                    {methods.formState.isSubmitting || isPending ? (
                                        <>
                                            <Loader2 className="w-4 h-4 animate-spin" />
                                            Saving...
                                        </>
                                    ) : (
                                        submitLabel || "Submit Changes"
                                    )}
                                </Button>
                            )
                        )}
                    </div>
                </form>
            </FormProvider>
        </TooltipProvider>
    );
};

export default HarmonyForm;
